# ---------- 辅助函数 ----------
def previous_prime(n):
    """返回小于n的最大素数"""
    n -= 1
    while not is_prime(n):
        n -= 1
    return n

def inv_extract_number(y):
    """MT19937的逆运算：从输出y恢复内部状态分量"""
    y ^= (y >> 18)
    y ^= ((y << 15) & 0xefc60000)
    y ^= ((y << 7) & 0x9d2c5680)
    y ^= ((y << 7) & 0x9d2c5680)
    y ^= ((y << 7) & 0x9d2c5680)
    y ^= ((y << 7) & 0x9d2c5680)
    y ^= ((y << 7) & 0x9d2c5680)
    y ^= ((y << 7) & 0x9d2c5680)
    y ^= ((y << 7) & 0x9d2c5680)
    y ^= ((y >> 11) & 0xffffffff)
    y ^= ((y >> 11) & 0xffffffff)
    return y

def recover_mt(outputs):
    """从624个连续32位输出恢复MT19937状态"""
    state = [inv_extract_number(x) for x in outputs[:624]]
    return (3, tuple(state + [0]), None)

