# 3. mail
K = Matrix(Zmod(q3), key3)
C = Matrix(Zmod(q3), cipher3).T
m = K.solve_right(C).T
mail = bytes([int(x) for x in m[0]])

# 4. 收集随机数输出（除了a,b）
# 从encrypt2中：randrange(start,end) 产生的随机数（31位）和 phone后面的160位
# 需要从q2的生成中提取随机数：q2 = next_prime( random.randrange(p2, p2+2^31-1) )
# 设 r2 = random.randrange(p2, p2+2^31-1)，则 q2 = next_prime(r2)
# 通过遍历previous_prime(q2)到q2得到r2，进而得到31位随机数（实际是32位低31位？）
# 这里简化：直接使用已知的随机数输出（从附件中提取），实际脚本中通过枚举得到
# 由于本脚本已包含所有随机数，我们直接使用预提取的ss列表（共618个）
# 注意：ss列表需要从encrypt2和encrypt3的原始数据中提取，这里省略提取过程，直接使用用户给出的ss
# 用户代码中的ss列表（前6个是encrypt2的，后面612个是encrypt3的key扁平化）
ss = [3156237697, 1049693302, 1113019088, 2934965650, 4044338613, 1644175009] + \
     [num for row in key3 for num in row]   # 共6+612=618个
# 但注意，key3中的数字已经是32位，但需要按顺序扁平化
# 实际上，用户代码中的ss列表与key3扁平化顺序一致，这里直接使用

# 枚举a,b（来自encrypt1）
p1_prime = p1  # p1是素数，a = previous_prime(p1)
q1_prime = q1
found = False
for a in range(previous_prime(p1), p1+1):
    for b in range(previous_prime(q1), q1+1):
        # a,b各96位，拆成3个32位
        a_vals = [(a >> (32*i)) & 0xffffffff for i in range(3)]
        b_vals = [(b >> (32*i)) & 0xffffffff for i in range(3)]
        all_rand = a_vals + b_vals + ss
        # 恢复MT19937状态
        state = recover_mt(all_rand)
        gen = Random()
        gen.setstate(state)
        # 跳过已经用掉的624个随机数（实际已经包含在all_rand中）
        # 预测下一个128位作为AES密钥
        key = long_to_bytes(gen.getrandbits(128))
        aes = AES.new(key, AES.MODE_ECB)
        try:
            address = aes.decrypt(long_to_bytes(c4)).decode()
            if re.match(r'^[\da-zA-Z\.\_]+$', address):
                address = address.encode()
                # 预测ElGamal私钥
                x = gen.randrange(q5-1)
                y = gen.randrange(q5-1)
                s = pow(h5, y, q5)
                # 或者直接用x：s = pow(c1_5, x, q5)
                # 验证一致性
                s_calc = pow(c1_5, x, q5)
                if s_calc == pow(h5, y, q5):
                    msg5 = c2_5 * invert(s_calc, q5) % q5
                    school = long_to_bytes(msg5)
                    found = True
                    break
        except:
            continue
    if found:
        break

if not found:
    raise Exception("未找到正确的a,b")

# 计算flag
flag = 'flag{' + sha256(name).hexdigest()[:8] + '-' + \
       sha256(phone).hexdigest()[:4] + '-' + \
       sha256(mail).hexdigest()[:4] + '-' + \
       sha256(address).hexdigest()[:4] + '-' + \
       sha256(school).hexdigest()[:12] + '}'
print(flag)